import { Injectable, Logger } from '@nestjs/common';
import { HttpService } from '@nestjs/axios';
import { ConfigService } from '@nestjs/config';
import { firstValueFrom } from 'rxjs';

@Injectable()
export class KybService {
  private readonly logger = new Logger(KybService.name);
  private readonly baseUrl: string;
  private readonly apiKey: string;
  private readonly appId: string;

  constructor(
    private readonly httpService: HttpService,
    private readonly configService: ConfigService,
  ) {
    this.baseUrl = 'https://api.prembly.com';
    this.apiKey = this.configService.get<string>('PREMBLY_API_KEY');
    this.appId = this.configService.get<string>('PREMBLY_APP_ID');
  }

  async verifyBusiness(registrationNumber: string, companyType: string) {
    const url = `${this.baseUrl}/open-api/business/cac/verify`;
    const headers = {
      'x-api-key': this.apiKey,
      'app-id': this.appId,
      'Content-Type': 'application/json',
    };

    const payload = {
      registration_number: registrationNumber,
      company_type: companyType,
    };

    this.logger.log(`Initiating business verification for: ${registrationNumber}`);

    try {
      const response = await firstValueFrom(
        this.httpService.post(url, payload, { headers }),
      );
      return response.data;
    } catch (error) {
      this.logger.error(`Error verifying business: ${error.message}`);
      if (error.response) {
        return error.response.data;
      }
      throw error;
    }
  }

  verifyWebhookSignature(signature: string, payload: any): boolean {
    const crypto = require('crypto');
    const secret = this.configService.get<string>('PREMBLY_WEBHOOK_SECRET') || this.apiKey;

    const hmac = crypto.createHmac('sha256', secret);
    const expectedSignature = hmac.update(JSON.stringify(payload)).digest('hex');

    return signature === expectedSignature;
  }
}

