import { Controller, Post, Body, HttpException, HttpStatus } from '@nestjs/common';
import { KybService } from './kyb.service';

@Controller('kyb')
export class KybController {
  constructor(private readonly kybService: KybService) {}

  @Post('verify')
  async verifyBusiness(@Body() body: { registrationNumber: string; companyType: string }) {
    if (!body.registrationNumber || !body.companyType) {
      throw new HttpException(
        'registrationNumber and companyType are required',
        HttpStatus.BAD_REQUEST,
      );
    }

    try {
      const result = await this.kybService.verifyBusiness(
        body.registrationNumber,
        body.companyType,
      );
      return result;
    } catch (error) {
      throw new HttpException(
        error.message || 'Verification failed',
        HttpStatus.INTERNAL_SERVER_ERROR,
      );
    }
  }
}

